window.LIVRES = [
  {id:"enquete",title:"Enquête à l'hôpital désaffecté",series:"Récit Express",totalPoints:17,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Combien de cambriolages ont eu lieu dans le quartier en une semaine selon le journal du père ?",options:["3 cambriolages","5 cambriolages","10 cambriolages","20 cambriolages"],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Au chapitre 1, pourquoi le père d'Eléna est-il décrit comme « terrorisé » plutôt que simplement « inquiet » ?",options:["Il a croisé les voleurs en bas de chez lui la nuit précédente.","Le dernier vol s'est produit dans la rue perpendiculaire à la leur, montrant que le danger est très proche.","Il sait que sa chienne Laïka est peureuse et ne pourra pas les défendre.","Les cambrioleurs ont volé la télévision du salon."],answer:1,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Eléna décide-t-elle de proposer à Erwan d'aller à l'hôpital désaffecté au chapitre 2 ?",options:["Elle espère y trouver des indices pour arrêter d'elle-même les voleurs.","Elle veut lui montrer qu'elle est plus courageuse que lui.","Elle cherche à faire une diversion pour qu'il arrête de parler des vols et ne se mette pas à enquêter.","Son frère Thomas lui a donné rendez-vous là-bas en secret."],answer:2,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Qui a initié Erwan et Eléna à la pratique de l'Urbex ?",options:["Le père d'Eléna","La grand-mère d'Erwan","Thomas, le grand frère d'Erwan","Un vigile de l'hôpital"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Au chapitre 4, pourquoi Eléna comprend-elle que les trois hommes en tenue de camouflage ne sont pas de vrais gardiens ?",options:["Ils portent des badges écrits à la main et n'ont pas de lampes torches.","Leurs vêtements sont sales et ils regardent tout le temps autour d'eux avec un air suspect.","Ils ont proposé aux enfants de partager leur butin avec eux.","Eléna connaît personnellement tous les vrais vigiles de la ville."],answer:0,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Où les trois cambrioleurs ont-ils installé leur cachette secrète dans l'hôpital ?",options:["Dans les anciennes cuisines du rez-de-chaussée.","Dans une pièce cachée derrière une grosse machine à laver à la cave.","Dans les combles, juste sous le toit qui s'écroule.","Dans l'ancienne ambulance garée dans le jardin."],answer:1,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Comment la police a-t-elle réussi à localiser la pièce où les enfants étaient retenus prisonniers ?",options:["La chienne Laïka a guidé les policiers en aboyant très fort.","Thomas est revenu des Alpes plus tôt que prévu et a prévenu le commissariat.","Erwan a laissé son téléphone secret connecté en ligne avec la police depuis sa poche.","Les voleurs avaient eux-mêmes appelé la police par erreur."],answer:2,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, pourquoi Eléna refuse-t-elle le téléphone portable offert par ses parents ?",options:["Elle préfère qu'ils lui offrent une collection de livres ou un ordinateur portable.","Elle a peur que les ondes soient mauvaises pour sa santé.","Elle ne veut pas qu'ils puissent la surveiller à tout moment (« un fil à la patte »).","Elle sait qu'Erwan en possède déjà un et que cela suffit pour deux."],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Chez les Bozelli, le petit déjeuner est habituellement un moment très bruyant où tout le monde parle.",answer:true,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Erwan est un garçon très têtu qui n'aime pas admettre qu'il a tort ou qu'il a eu peur.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"La chienne Laïka attaque courageusement les bandits pour protéger Eléna et Erwan.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"À la fin du récit, la mère d'Eléna la taquine en insinuant qu'Erwan est son amoureux.",answer:true,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« si les voleurs avaient l'idée saugrenue » — Que signifie saugrenue ?",options:["Une idée brillante et très bien préparée.","Une idée bizarre, absurde ou ridicule.","Une idée généreuse pour aider les autres."],answer:1,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« l'exploration de sites urbains désaffectés » — Que signifie désaffectés ?",options:["Des bâtiments modernes qui viennent d'être construits.","Des lieux qui ne sont plus utilisés pour leur fonction d'origine et sont laissés vides.","Des maisons très bien décorées et habitées par des familles."],answer:1,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Au bout d'une heure de déambulations vaines » — Que signifie vaines ?",options:["Qui se font dans la joie et la bonne humeur générale.","Qui sont interdites par la loi ou dangereuses pour la santé.","Qui sont inutiles et n'ont donné aucun résultat concret."],answer:2,points:1},
    {id:"q16",section:"Vocabulaire",type:"mcq",text:"« Erwan et moi on a obtempéré » — Que signifie obtempéré ?",options:["Obéir à un ordre sans protester.","Se mettre à crier très fort pour appeler à l'aide.","S'enfuir en courant le plus vite possible."],answer:0,points:1},
    {id:"q17",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Erwan retourne seul à l'hôpital, découvre le butin, puis les enfants piègent les voleurs en les enfermant à clé avant d'appeler les secours.","Résumé B : Eléna et Erwan découvrent la cachette, sont faits prisonniers à la cave, et sont libérés grâce au téléphone secret d'Erwan connecté à la police.","Résumé C : Les enfants demandent immédiatement de l'aide à Thomas et à la police, qui fouillent le bâtiment sous leur direction."],answer:1,points:1}
  ]},
  {id:"longs_nuages",title:"Au pays des longs nuages blancs",series:"Récit Express",totalPoints:17,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi la mère d'Alice se retrouve-t-elle à l'hôpital en Nouvelle-Zélande ?",options:["Elle a été attaquée par un Maori lors d'une randonnée.","Elle est tombée d'un parapente et s'est cassé une jambe et les deux bras.","Elle a eu un accident de voiture sur l'autoroute d'Auckland.","Elle s'est noyée en faisant de la plongée près de Great Barrier."],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Comment Alice et son père se rendent-ils sur l'île de Great Barrier ?",options:["En ferry régulier depuis Auckland.","En hélicoptère avec le vieux Bill.","En cargo de marchandises, car le ferry n'était plus rentable.","En bateau à moteur avec la mère d'Alice."],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Qu'est-ce qu'Alice découvre dans le cabanon au sommet de la falaise ?",options:["Des bijoux et des vêtements traditionnels maoris.","Des caisses, du matériel de pêche, de la corde et un fusil à lunette.","Des cartes géographiques et des relevés de sa mère.","Un autel maori avec des statuettes et des offrandes."],answer:1,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi le Zodiac de Bill coule-t-il pendant la partie de pêche ?",options:["Le moteur tombe en panne et le bateau prend l'eau.","Une vague géante renverse l'embarcation.","Deux balles tirées depuis la côte percent les boudins du Zodiac.","Tobby saute dans le bateau et déséquilibre l'embarcation."],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Alice dit que son cœur était « comme un cheval arrêté au milieu du gué ». Que veut-elle exprimer ?",options:["Elle était tellement fatiguée qu'elle ne pouvait plus bouger.","Elle était suspendue entre espoir et angoisse, sans savoir ce qui allait arriver.","Elle était en colère contre son père qui refusait de lui parler.","Elle avait tellement peur qu'elle voulait s'enfuir en courant."],answer:1,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Alice n'avoue-t-elle pas à ses parents qu'elle a découvert le cabanon et le Maori dans la forêt ?",options:["Elle voulait garder le secret pour pouvoir y retourner seule le lendemain.","Elle avait promis de ne pas prendre les sentiers non balisés et avait pénétré sur une propriété privée.","Elle avait peur que ses parents la renvoient en France.","Elle ne voulait pas effrayer sa mère qui était encore fragile après son accident."],answer:1,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Pita Witkaire a-t-il tiré sur le Zodiac de Bill et d'Alice ?",options:["Il voulait voler le matériel de pêche de Bill.","Il pensait que Bill était un pêcheur à la dynamite venu détruire les fonds marins.","Il était fou de rage car des pêcheurs blancs avaient tué son dauphin ami, et il ne supportait plus les bateaux de pêche dans la baie.","Il voulait effrayer les touristes pour les forcer à quitter l'île."],answer:2,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Pita sourit-il pour la première fois lorsqu'il emmène Alice voir les dauphins ?",options:["Il est soulagé de ne pas avoir été dénoncé à la police.","Il est heureux de voir que les dauphins reviennent nager près de la côte, signe que la nature reprend ses droits.","Il est content d'avoir trouvé de nouvelles langoustes pour le repas de Noël.","Il est fier de montrer à Alice à quel point il connaît bien la mer."],answer:1,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Alice et son père partent en Nouvelle-Zélande depuis l'aéroport de Roissy, avec une escale à Singapour.",answer:true,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Le vieux Bill est un ancien médecin australien qui s'est installé à Great Barrier pour sa retraite.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Les opossums ont été introduits en Nouvelle-Zélande depuis l'Australie et causent de graves dégâts dans les forêts.",answer:true,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"À la fin du récit, Pita et ses amis maoris dansent le haka pour dire au revoir à Alice et sa famille.",answer:true,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« délicieusement vivifiant » — Que signifie vivifiant ?",options:["Qui donne envie de dormir et de se reposer.","Qui réveille et redonne de l'énergie et de la vitalité.","Qui sent mauvais et devient vite insupportable.","Qui est si fort qu'il renverse tout sur son passage."],answer:1,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« une figurine qui grimaçait de manière assez effrayante » — Que signifie effrayante ?",options:["Qui provoque une grande admiration.","Qui fait rire tellement c'est exagéré et ridicule.","Qui provoque la peur ou l'inquiétude chez celui qui la voit.","Qui est tellement vieille qu'elle tombe en morceaux."],answer:2,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« le terrain était jonché de racines, de lianes enchevêtrées » — Que signifie enchevêtrées ?",options:["Soigneusement rangées et bien alignées les unes à côté des autres.","Emmêlées et entrelacées dans tous les sens, formant un fouillis.","Coupées et déposées en tas sur le bord du chemin.","Totalement sèches et mortes depuis de nombreuses années."],answer:1,points:1},
    {id:"q16",section:"Vocabulaire",type:"mcq",text:"« une amitié mystique était née entre l'homme et l'animal » — Que signifie mystique ?",options:["Qui repose sur des intérêts communs et des échanges commerciaux.","Qui est difficile à expliquer rationnellement et semble tenir du sacré ou du spirituel.","Qui est construite grâce à de nombreuses années de pratique sportive ensemble.","Qui est connue de tous et dont tout le monde parle dans la région."],answer:1,points:1},
    {id:"q17",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : La mère d'Alice tombe d'un parapente. Lors d'une sortie en mer, le Zodiac est coulé par des pêcheurs à la dynamite. Alice comprend que c'est le Maori Pita qui a tiré. Ils deviennent amis.","Résumé B : La mère d'Alice se blesse lors d'une randonnée. Ils se rendent à Great Barrier. Le bateau est coulé par des coups de fusil. Pita leur explique sa douleur. Ils deviennent amis et Pita danse le haka en guise d'adieu.","Résumé C : La mère d'Alice tombe d'un parapente. Ils prennent un cargo jusqu'à Great Barrier. Alice découvre Pita qui coule le Zodiac. Pita explique la mort de son dauphin. Ils deviennent amis. Pita offre le spectacle de dauphins et danse le haka la veille du départ."],answer:2,points:1}
  ]},
  {id:"au_dessus_nuages",title:"Au-dessus des nuages",series:"Récit Express",totalPoints:17,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Marine ne voit-elle son père que le temps d'un weekend ?",options:["Son père travaille à l'étranger et ne rentre qu'une fois par mois.","Ses parents sont séparés et elle vit avec sa mère le reste du temps.","Son père est hospitalisé et n'a le droit de recevoir des visites que le weekend.","Marine passe ses semaines en internat et rentre chez son père le weekend."],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Que trouve Marine dans le gros sac en toile épaisse au fond du débarras ?",options:["Des photos de famille et des souvenirs d'enfance de son père.","Des vêtements et des jouets qu'elle avait oubliés chez son père.","Une énorme bâche qui servait à fabriquer une montgolfière.","Du matériel de camping que son père utilisait autrefois."],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Marine demande-t-elle à sa mère de lui apprendre à coudre ?",options:["Elle veut fabriquer des vêtements pour les offrir à son père.","Elle doit réparer les trous dans la toile de la montgolfière.","Son cours de couture à l'école lui demande de s'entraîner à la maison.","Elle veut confectionner une surprise pour l'anniversaire de sa mère."],answer:1,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Lors du premier vol d'essai, pourquoi Alain monte-t-il seul dans la montgolfière ?",options:["La nacelle est trop petite pour accueillir deux personnes à la fois.","Marine a trop peur et refuse de monter dans l'engin.","Il doit faire des vols d'essai seul pour vérifier que tout est sûr avant d'emmener sa fille.","L'autorisation de vol ne lui permet d'emmener qu'un seul passager à la fois."],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Alain « restait cloué dans ses pantoufles noires » et ses amis avaient arrêté de le voir. Qu'est-ce que cela révèle sur son état ?",options:["Il est devenu très solitaire par choix et préfère rester seul.","Il est tellement déprimé qu'il ne fait plus rien et s'isole de tout le monde.","Il est très occupé par sa recherche d'emploi et n'a plus le temps de voir personne.","Il est en colère contre ses amis qui ne comprennent pas sa situation."],answer:1,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Marine ne révèle-t-elle pas son projet à son père au moment où elle cherche la nacelle ?",options:["Elle veut lui faire une surprise totale et ne lui dire qu'au dernier moment.","Elle sait que si elle lui explique, il refusera catégoriquement de participer.","Elle a peur qu'il vende la montgolfière avant qu'elle puisse la réparer.","Elle ne veut pas qu'il sache qu'elle a fouillé dans ses affaires sans permission."],answer:0,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Quand Alain jette les sacs de sable avant le décollage, le narrateur compare chaque sac à un souci. Que signifie ce moment ?",options:["Alain réalise que les sacs sont trop lourds et qu'il faut alléger la montgolfière pour voler.","En lâchant les lests, Alain commence symboliquement à se débarrasser de ses problèmes.","Alain est en colère et jette les sacs par terre pour montrer sa frustration.","Les sacs représentent les cadeaux qu'Alain veut offrir à Marine pendant le vol."],answer:1,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, Alain envisage de proposer des tours de montgolfière aux touristes. Qu'est-ce que cela montre ?",options:["Il cherche uniquement à rembourser les frais engagés pour réparer la montgolfière.","Il a retrouvé l'envie de se battre et transforme sa passion en projet professionnel.","Il veut prouver à son ancienne femme qu'il est capable de gagner de l'argent.","Il souhaite passer plus de temps avec Marine en faisant quelque chose ensemble."],answer:1,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"La montgolfière avait déjà été utilisée par le père d'Alain et Alain lui-même lorsqu'il était plus jeune.",answer:true,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"C'est la mère de Marine qui propose d'aller chercher la nacelle dans la remise du grand-père.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Le jour du grand vol, la météo est mauvaise et il y a beaucoup de nuages dans le ciel.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"À la fin de l'histoire, la mère de Marine a collé une montgolfière phosphorescente au plafond de la chambre de sa fille.",answer:true,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« L'émotion était palpable chez la jeune fille de dix ans. » — Que signifie palpable ?",options:["Qu'on peut ressentir très clairement, comme si on pouvait presque la toucher.","Qui est cachée et difficile à remarquer pour ceux qui l'entourent.","Qui disparaît très vite et ne dure que quelques secondes.","Qui est fausse et jouée pour attirer l'attention des autres."],answer:0,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« le débarras, qui servait de grenier » — Que signifie débarras ?",options:["Une grande pièce lumineuse spécialement aménagée pour les enfants.","Une pièce où l'on range en désordre des objets dont on ne se sert plus.","Un garage où l'on gare les vélos et les voitures de la famille.","Une bibliothèque remplie de livres et de documents importants."],answer:1,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« De leur méticulosité dépendaient la réussite et la sécurité du vol. » — Que signifie méticulosité ?",options:["Le fait d'agir vite et sans réfléchir pour terminer le travail le plus tôt possible.","La chance et le hasard qui font que les choses se passent bien ou mal.","Le soin apporté aux moindres détails pour que le travail soit parfait.","La force physique nécessaire pour soulever des objets très lourds."],answer:2,points:1},
    {id:"q16",section:"Vocabulaire",type:"mcq",text:"« Jamais elle n'avait ressenti autant de tension. » — Que signifie tension ?",options:["Un sentiment de grande fatigue après un long effort physique.","Un état d'inquiétude mêlé d'excitation face à quelque chose d'important et d'incertain.","Une forte envie de dormir causée par l'ennui et l'attente.","Une colère difficile à contrôler contre quelqu'un qui nous a déçu."],answer:1,points:1},
    {id:"q17",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Marine découvre la montgolfière. Avec sa mère, elle la répare. Son père accepte et lors d'un premier essai, ils volent ensemble pour la première fois. Ce vol lui redonne le sourire et il lance une activité de tours en montgolfière.","Résumé B : Marine découvre la montgolfière. Avec sa mère, elle la répare. Son père fait d'abord un vol d'essai seul, puis ils s'envolent ensemble lors du weekend suivant. Ce vol redonne à Alain l'envie de vivre et il envisage des tours en montgolfière pour les touristes.","Résumé C : Marine découvre la montgolfière que son père avait construite seul. Elle apprend à coudre avec sa grand-mère. Ils font ensemble un premier vol d'essai parfait. Ce vol lui donne l'idée de devenir pilote professionnel."],answer:1,points:1}
  ]},
  {id:"pays_neige",title:"Aventures au pays de la neige",series:"Récit Express",totalPoints:17,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Comment Francis et Frédéric trouvent-ils le portefeuille de Mathieu Roy ?",options:["Ils le voient tomber de la poche de Mathieu dans la rue.","Ils le découvrent en cherchant le gant perdu de Frédéric dans la neige.","Ils le ramassent sur un banc à l'entrée du Château Frontenac.","Un passant le leur remet en les voyant se promener dans la rue."],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi font-ils réciter à Mathieu des informations sur lui-même avant de lui rendre son portefeuille ?",options:["Ils veulent lui montrer qu'ils ont bien mémorisé son identité.","Ils s'ennuient et cherchent à passer le temps en attendant leurs parents.","Ils veulent s'assurer qu'il est bien le vrai propriétaire et non un imposteur.","Ils espèrent obtenir une récompense plus importante en impressionnant Mathieu."],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Que propose Mathieu aux deux frères pour les récompenser de leur honnêteté ?",options:["Il leur offre de l'argent pour acheter de nouveaux jeux vidéo.","Il leur propose de passer une journée au Centre de vacances Champlain.","Il leur offre deux abonnements annuels gratuits à un club de ski.","Il les invite à dîner dans un des restaurants du Château Frontenac."],answer:1,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Qu'est-ce que Francis aperçoit dans la cabane blanche qui l'alerte sur la situation de Mathieu ?",options:["Il voit le cadenas forcé et la porte défoncée.","Il aperçoit des trophées brisés éparpillés sur le sol.","Il voit Mathieu ligoté et immobile par la fenêtre.","Il découvre un message d'alerte laissé par Mathieu sur la porte."],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Francis dit que marcher « lui oxygène le cerveau et avive son goût d'aventure ». Qu'est-ce que cela révèle sur son caractère ?",options:["C'est un garçon sportif qui préfère toujours courir plutôt que marcher.","C'est un garçon curieux et vif d'esprit qui s'épanouit au contact de la nature.","C'est un garçon timide qui n'aime pas rester en intérieur avec les autres.","C'est un garçon compétitif qui cherche toujours à dépasser son frère."],answer:1,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Lorsque Francis reste seul dans le télésiège, il se cache le visage dans son foulard. Pourquoi ?",options:["Il a très froid et veut se protéger du vent glacial du sommet.","Il est tellement concentré qu'il ne réalise pas ce qu'il fait.","Il a honte de sa peur et ne veut pas être reconnu par la foule qui le regarde.","Il veut imiter les snowboardeurs professionnels qu'il a vus faire de même."],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Dans le button, Francis entend parler de « quatre compétitions », d'une « manne de cuivre » et le mot « Bingo ». Que laisse deviner ces mots ?",options:["Ce sont des employés qui discutent du programme des compétitions.","Ce sont deux spectateurs qui commentent les résultats des finales.","Ce sont les deux complices qui planifient le vol des trophées en métal.","Ce sont des organisateurs qui préparent la remise des prix."],answer:2,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, le père de Francis et Frédéric décide de se remettre en forme. Qu'est-ce qui explique ce changement ?",options:["Il a honte que ses fils soient plus courageux que lui face à la neige et au froid.","La journée au Centre Champlain et l'aventure vécue par ses fils lui ont redonné le goût du sport.","Mathieu lui a proposé un emploi au Centre Champlain s'il reprenait le sport.","Monsieur Jutras lui a offert un abonnement gratuit pour lui redonner envie de skier."],answer:1,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Francis et Frédéric sont jumeaux et ont tous les deux dix ans.",answer:true,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Le père de Francis et Frédéric les accompagne toute la journée au Centre de vacances Champlain.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Les trophées volés par Kevin et Sacha étaient en or massif.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"C'est grâce à un patrouilleur de ski croisé par hasard que Francis peut donner l'alerte pour secourir Mathieu.",answer:true,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Notre recherche est plus ardue qu'elle ne paraît. » — Que signifie ardue ?",options:["Qui se fait rapidement et sans aucune difficulté.","Qui est longue, difficile et demande beaucoup d'efforts.","Qui est inutile car le résultat est connu d'avance.","Qui est amusante et transformée en jeu par les deux frères."],answer:1,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Je veux vous récompenser pour votre droiture. » — Que signifie droiture ?",options:["La rapidité avec laquelle ils ont retrouvé le portefeuille dans la neige.","L'intelligence dont ils ont fait preuve pour identifier le propriétaire.","L'honnêteté et le sens moral qui les ont poussés à rendre le portefeuille.","La politesse et le respect qu'ils ont montrés en rencontrant un adulte inconnu."],answer:2,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Le château de glace est une construction éphémère. » — Que signifie éphémère ?",options:["Qui est solide et résistante, construite pour durer de nombreuses années.","Qui n'existe que pour une courte durée et est destinée à disparaître.","Qui est très grande et impressionnante par sa taille et ses dimensions.","Qui est fragile et risque de s'effondrer à cause du poids de la neige."],answer:1,points:1},
    {id:"q16",section:"Vocabulaire",type:"mcq",text:"« Ma curiosité est aiguisée. » — Que signifie aiguisée ?",options:["Rendue plus vive et plus intense, comme une lame qu'on affûte.","Calmée et apaisée après une longue journée de sport dans la neige.","Transformée en peur à l'idée de découvrir quelque chose de dangereux.","Partagée avec son frère qui ressent exactement la même chose que lui."],answer:0,points:1},
    {id:"q17",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Les jumeaux trouvent un portefeuille, le rendent à Mathieu au Château Frontenac. Il les invite au Centre Champlain. Francis tombe dans un button. Il découvre Mathieu ligoté. Grâce à ses parents alertés par téléphone, les voleurs sont arrêtés.","Résumé B : Les jumeaux trouvent un portefeuille, le rendent à Mathieu. Il les invite au Centre Champlain. Francis entend les complices dans un button, découvre Mathieu ligoté. Un patrouilleur donne l'alerte. Francis reconnaît la voix d'un complice et fait arrêter les voleurs.","Résumé C : Les jumeaux trouvent un portefeuille et invitent Mathieu chez eux. Ils vont au Centre Champlain. Francis glisse dans un button et entend parler d'un vol. Il retrouve Mathieu blessé. Avec son frère, il brise le cadenas et libère Mathieu avant de dénoncer les voleurs."],answer:1,points:1}
  ]},
  {id:"college_momiji",title:"Collège Momiji",series:"Récit Express",totalPoints:17,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Aiko a-t-elle fugué du collège Momiji ?",options:["Elle ne supportait plus les règles strictes du pensionnat.","Elle avait vécu des phénomènes étranges et terrifiants qui lui faisaient craindre pour sa vie.","Elle s'était disputée avec son amie Yui.","Elle avait reçu de mauvais résultats scolaires."],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Quelle règle particulière du collège Momiji concernait les tablettes des élèves ?",options:["Les tablettes étaient interdites.","Les jeux étaient effacés des tablettes le jour de l'entrée et Internet n'était disponible qu'en classe.","Les élèves ne pouvaient utiliser leur tablette qu'une heure par soir.","Les tablettes étaient rangées dans un casier fermé à clé pendant toute la semaine."],answer:1,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Que découvre Aiko sous son lit au petit matin après sa nuit d'épouvante ?",options:["Un rat qui avait fait du bruit toute la nuit.","Une petite poupée couverte de poussière blanche et sans visage.","La poupée de Yui qui avait mystérieusement quitté la chambre de son amie.","Un message écrit sur un bout de papier par une main inconnue."],answer:1,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Comment Aiko parvient-elle à détruire les deux poupées maléfiques ?",options:["Elle les brûle dans la cheminée de la salle commune.","Elle les jette dans la rivière qui longe le jardin du pensionnat.","Elle les place dans un four à micro-ondes jusqu'à ce qu'elles prennent feu.","Elle les brise contre le mur de sa chambre."],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Aiko utilise l'écran noir de sa tablette éteinte comme miroir. Que cela révèle-t-il sur les règles du pensionnat ?",options:["Les tablettes sont interdites d'utilisation le matin.","Les miroirs sont interdits dans les chambres, ce qui pousse Aiko à trouver une autre solution pour se voir.","L'électricité est coupée dans les chambres le matin pour économiser de l'énergie.","Aiko préfère éviter les douches communes car elle est timide."],answer:1,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Quand Yui cite deux haïkus qu'Aiko venait de lire le jour même, Aiko pense « Quel hasard ». Que comprend-on en réalité ?",options:["Yui est une excellente élève qui connaît par cœur tous les grands poètes japonais.","C'est effectivement une coïncidence car ces haïkus sont très connus au Japon.","Yui est déjà sous l'influence de la poupée et possède des pouvoirs qui lui permettent de lire dans les pensées d'Aiko.","Yui a regardé dans les livres d'Aiko pendant la journée pour lui faire une surprise."],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Aiko retourne-t-elle chercher la poupée avant de fuir, alors qu'elle a très peur ?",options:["Elle veut emporter la poupée comme preuve pour montrer à ses parents.","Elle sait que si elle ne détruit pas la poupée, celle-ci lui volera son visage et son âme.","Elle veut retrouver sa tablette qu'elle a oubliée.","Elle souhaite libérer Yui en échangeant la poupée maléfique contre la belle poupée de l'impératrice."],answer:1,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"La radio annonce que tous les élèves et professeurs d'un collège ont disparu et qu'on a retrouvé autant de poupées. Que laisse entendre cette fin ?",options:["La police a résolu l'affaire.","Le phénomène de Momiji s'étend à d'autres établissements et la menace est bien réelle.","Les parents d'Aiko vont enfin la croire et appeler immédiatement la police.","Momiji est le seul collège touché."],answer:1,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Le collège Momiji tire son nom du mot japonais qui signifie « cerisier ».",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Aiko a choisi le collège Momiji notamment parce qu'il proposait des cours de calligraphie et de composition poétique.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"La préfète de discipline laisse partir Aiko et Yui parce qu'elle croit qu'elles se rendent chez le proviseur pour préparer la fête des poupées.",answer:true,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"À la fin de l'histoire, le père d'Aiko décide de croire sa fille et renonce à la ramener au collège Momiji.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Aiko réajuste consciencieusement les plis de sa jupe bleue. » — Que signifie consciencieusement ?",options:["Rapidement et sans faire attention.","Avec beaucoup de soin et d'attention, en veillant à bien faire les choses.","Machinalement et sans y penser.","Maladroitement, car elle tremble trop de peur."],answer:1,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« ce lieu était magnifique... c'était un havre de paix » — Que signifie havre de paix ?",options:["Un endroit bruyant et animé.","Un lieu de refuge calme et agréable où l'on se sent à l'abri et tranquille.","Un bâtiment très ancien qui n'est plus entretenu.","Un endroit dangereux que l'on évite."],answer:1,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Elle se mit à les feuilleter fébrilement. » — Que signifie fébrilement ?",options:["Lentement et avec précaution.","D'une manière agitée et fébrile, avec une excitation mêlée d'inquiétude.","Avec ennui et sans conviction.","Méthodiquement et dans l'ordre."],answer:1,points:1},
    {id:"q16",section:"Vocabulaire",type:"mcq",text:"« Cette chose était une larve en train de préparer sa mue. » — Que signifie mue dans ce contexte ?",options:["La destruction totale de la poupée.","La transformation qui allait lui permettre de changer d'apparence et de prendre la place d'Aiko.","Le bruit inquiétant que faisait la poupée.","Le sortilège ancien que la poupée allait lancer sur toutes les élèves."],answer:1,points:1},
    {id:"q17",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Aiko vit des phénomènes étranges à Momiji. Son amie Yui est touchée. Aiko détruit les poupées dans un four et libère son amie. Les deux filles fuient. La radio annonce que tous les élèves et professeurs d'un autre collège ont disparu, remplacés par des poupées.","Résumé B : Aiko fugue de Momiji. Elles brûlent les poupées dans la cheminée. Elles trompent la préfète en prétendant se rendre chez le professeur de poésie.","Résumé C : Aiko vit des phénomènes étranges à Momiji. Elle détruit les poupées dans un four. Les deux filles fuient et trompent la préfète. De retour chez ses parents, son père décide finalement de croire Aiko et appelle la police."],answer:0,points:1}
  ]},
  {id:"etoiles_filantes",title:"Étoiles filantes",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Où Nicolas et Marie passent-ils leurs vacances ?",options:["Chez leurs parents à la ville","Dans un camping à la campagne","Chez leurs grands-parents à la campagne","Dans la maison du père Henri"],answer:2,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Comment Django a-t-il prévenu Nicolas du rendez-vous ?",options:["En lui parlant à travers la haie","En glissant un mot sous la porte de la maison","En déposant une lettre dans la cabane","En demandant à un enfant du camp de le prévenir"],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Qui est Manuel dans l'histoire ?",options:["Le gendarme du village","Le voisin de grand-mère","L'antiquaire dont les meubles ont été volés","Le père de Django et chef du campement"],answer:3,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Qui a réellement volé les meubles chez Hubert l'antiquaire ?",options:["Django et son père Manuel","Des inconnus jamais retrouvés","« P'tit Louis », un homme du village","Un groupe de gitans d'un autre camp"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi grand-mère ferme-t-elle les volets en plein après-midi au chapitre 1 ?",options:["Parce qu'il fait trop chaud et trop de soleil","Parce que les enfants ont fait une bêtise","Parce qu'un orage menace","Parce qu'elle a peur des romanichels arrivés dans le village"],answer:3,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Nicolas place-t-il un drapeau blanc sur la cabane ?",options:["Pour décorer la cabane comme Marie le lui a demandé","Pour indiquer à grand-père que la cabane est terminée","Pour signaler à Django qu'il accepte le rendez-vous","Pour marquer l'emplacement de la cabane dans le jardin"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"À la fin du récit, Nicolas dit : « Je m'en veux d'avoir douté. » Pourquoi a-t-il douté de Django ?",options:["Parce que Django lui avait menti sur l'heure de la fête","Parce que les rumeurs du village l'ont fait soupçonner que les gitans étaient coupables du vol","Parce que Django avait disparu sans lui dire au revoir","Parce que la lettre de Django était mal écrite et confuse"],answer:1,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"Dans le conte des étoiles, que représentent les étoiles filantes selon Manuel ?",options:["Les gens riches qui voyagent pour leur plaisir","Les enfants qui rêvent de liberté","Les Roms et tous les nomades qui refusent de se fixer comme les sédentaires","Les étoiles les plus brillantes du ciel"],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Grand-père pense, comme grand-mère, que les enfants ne doivent pas sortir à cause des romanichels.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Django a déjà vécu dans une maison, dans un internat, pour aller à l'école.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Nicolas raconte à grand-mère qu'il a passé la nuit au camp des gitans.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"À la fin de l'histoire, Nicolas revoit Django quelques années plus tard.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« On s'est regardés, interloqués. » — Que signifie interloqués ?",options:["Très en colère et prêts à se disputer","Très fatigués après avoir longtemps travaillé","Tellement surpris qu'on ne sait plus quoi dire","Très contents et soulagés"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Grand-mère venait de refermer à double tour la porte en marmonnant entre ses dents. » — Que signifie marmonnant ?",options:["En criant très fort pour que tout le monde entende","En chantant doucement pour se calmer","En pleurant de peur et d'inquiétude","En parlant tout bas, de façon peu compréhensible"],answer:3,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Je m'attendais à découvrir des dégâts un peu partout, comme la trace d'un ouragan. » — Que signifie ouragan ?",options:["Un animal sauvage et dangereux","Une tempête violente et destructrice","Un incendie qui se répand rapidement","Un groupe de personnes qui se disputent bruyamment"],answer:1,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Nicolas et Marie passent leurs vacances chez leurs grands-parents. Nicolas reçoit une lettre de Django dans la cabane, va à la fête en secret, est chaleureusement accueilli et entend le conte des étoiles. Le lendemain, les gitans sont accusés d'un vol mais c'est « P'tit Louis » le coupable. Nicolas ne reverra jamais Django.","Résumé B : Nicolas montre la lettre de Django aux gendarmes pour prouver leur innocence.","Résumé C : Django glisse une lettre sous la porte de la maison. La fête est triste. Nicolas avoue à grand-mère qu'il était au camp cette nuit-là."],answer:0,points:1}
  ]},
  {id:"controle_geo",title:"Le contrôle de géo n'aura pas lieu",series:"Récit Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Qui a eu l'idée de faire un vœu collectif pour éviter le contrôle ?",options:["Damien","Laura","Théo","Séb"],answer:2,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Que fait Damien pour tenter de se faire passer pour malade le mercredi soir ?",options:["Il appelle le médecin","Il met le thermomètre dans l'eau chaude","Il chauffe le thermomètre au-dessus du radiateur","Il avale des médicaments"],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Qu'est-ce qui provoque l'interruption du contrôle le jeudi matin ?",options:["Une panne de chauffage","La grippe du professeur Bertin","Une lumière aveuglante suivie de tremblements","Une alarme incendie"],answer:2,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Avec quoi Théo fabrique-t-il le radeau ?",options:["Des tables et des chaises","Des planches trouvées dans le couloir","Des morceaux de polystyrène découpés en salle d'Arts Plastiques","Des portes arrachées de leurs gonds"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Damien hésite-t-il à avouer qu'il n'a tenu que cinq minutes lors du vœu collectif ?",options:["Il a peur de la punition de ses parents","Il veut paraître courageux devant le professeur","Il ne veut pas perdre la face devant ses amis","Il a oublié ce qui s'était passé"],answer:2,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Quand Damien reconnaît l'odeur sucrée sur le « caillou », à quoi cela fait-il référence ?",options:["À un souvenir d'enfance","À son goûter de l'après-midi","À la bande dessinée L'Étoile mystérieuse qu'il avait lue la veille","Au menu de la cantine"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Laura nie-t-elle avec tant d'énergie que son vœu est responsable de la tempête de neige ?",options:["Elle est certaine d'avoir raison scientifiquement","Elle a oublié quel vœu elle avait fait","Elle sait probablement que son vœu est lié, mais elle a honte de l'admettre","Elle veut protéger Théo"],answer:2,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin du livre, on comprend que toute l'aventure était en réalité...",options:["Un souvenir raconté à ses petits-enfants","Une histoire inventée par Damien pour ses amis","Un rêve fiévreux de Damien","Un film regardé en classe"],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Le professeur Bertin est le professeur principal de la classe.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Séb tente en premier de convaincre le professeur d'annuler le contrôle.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Le morceau de comète s'écrase directement sur la ville de Rouen.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"À la fin, le contrôle de géographie a bien eu lieu le lundi suivant.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Séb s'est insurgé » — Que signifie s'est insurgé ?",options:["Approuvé avec enthousiasme","Répondu poliment","Protesté avec indignation","Chuchoté discrètement"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Bertin l'a toisé, le sourcil gauche en accent circonflexe. » — Que signifie toisé ?",options:["Ignoré complètement","Félicité chaleureusement","Interrogé à voix haute","Regardé de haut avec mépris"],answer:3,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« J'échafaude des scénarios de plus en plus farfelus. » — Que signifie farfelus ?",options:["Dangereux et risqués","Tristes et dramatiques","Bizarres et extravagants","Ennuyeux et répétitifs"],answer:2,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Damien et ses amis font un vœu collectif. Une comète s'écrase dans l'Arctique, provoquant des bouleversements. Les quatre amis s'échappent sur un radeau. Damien tombe à l'eau et se réveille dans son lit : tout était un rêve de fièvre. En réalité, c'est le professeur Bertin qui était absent ce jour-là.","Résumé B : La comète s'écrase directement sur Rouen, détruisant leur collège. Le contrôle a finalement bien eu lieu le jeudi comme prévu.","Résumé C : Des miettes de céréales se transforment en virus géants. Séb sauve tout le groupe et ils rentrent sains et saufs au collège."],answer:0,points:1}
  ]},
  {id:"goutte_eau",title:"La goutte d'eau qui…",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Line affiche-t-elle des avis de recherche dans le quartier ?",options:["Pour retrouver son grand frère Jérôme parti au Canada","Pour signaler la disparition de son chat Catsou","Pour retrouver Catsou, le chat de son frère qu'elle gardait et qui a disparu","Pour trouver quelqu'un qui accepte de garder son chat pendant les vacances"],answer:2,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Comment Line rencontre-t-elle Charlotte pour la première fois ?",options:["Charlotte est une voisine qui vient frapper à sa porte","C'est Assia qui lui présente Charlotte lors d'une sortie","Line la rencontre lors du cours de cyclodanse","Charlotte l'appelle après avoir trouvé l'avis de recherche de Catsou dans sa boîte aux lettres"],answer:3,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Quel est le sujet de l'exposé que Monsieur Briard demande à ses élèves ?",options:["Un portrait de quelqu'un de la famille","Une présentation d'un sport paralympique","Une interview d'une personne passionnée, présentée à la classe avec des panneaux ou un PowerPoint","Un reportage photo sur un métier du quartier"],answer:2,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Monsieur Briard quitte-t-il la classe en claquant la porte lors de l'exposé de Line ?",options:["Il trouve le sujet de Line trop peu original","Line a commis une erreur grave dans sa présentation","Il reconnaît Charlotte sur les photos, sa belle-fille avec qui il est brouillé depuis deux ans","Il est soudainement pris d'un malaise physique"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Quand Line dit à Charlotte : « C'est de votre faute s'il est mort ! C'est parce que vous êtes handicapée ! », qu'est-ce qui explique cette réaction ?",options:["Line est convaincue que Charlotte aurait pu appeler les secours et ne l'a pas fait","Line est jalouse de Charlotte et cherche une raison de se disputer avec elle","Line est trop petite pour voir que Charlotte est en fauteuil","Line est dévastée par la mort de Catsou et rejette sa douleur sur la première personne disponible, sans chercher à comprendre"],answer:3,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Charlotte montre à Line que Catsou était sur un mur de quatre mètres quand elle l'a vu. Que comprend Line à ce moment-là ?",options:["Que Charlotte aurait quand même dû appeler du secours pour elle","Que Catsou a grimpé là-haut pour s'échapper du jardin de Charlotte","Que même une personne valide n'aurait pas pu le récupérer, et que ses accusations étaient à la fois injustes et fausses","Que Catsou souffrait depuis longtemps"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"À la fin du récit, le papa de Line rougit et bafouille qu'il faudra « aller remercier Charlotte un de ces jours ». Que laisse entendre ce détail ?",options:["Que le papa de Line veut demander à Charlotte des conseils pour son travail de photographe","Que le papa de Line est peut-être en train de tomber amoureux de Charlotte","Que le papa de Line se sent coupable de ne pas avoir aidé Line à retrouver Catsou","Que le papa de Line souhaite faire un reportage photo sur la cyclodanse"],answer:1,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, Line décide d'appeler sa chatte « Droppy ». Pourquoi ce nom est-il particulièrement bien choisi dans ce récit ?",options:["Parce que la chatte est toute petite et fragile comme une goutte d'eau","Parce que Line veut lui donner un nom anglais en hommage à son frère parti au Canada","Parce que la chatte est tombée dans une flaque d'eau quand Line l'a rencontrée","Parce que « drop » signifie « goutte d'eau » en anglais, et que c'est Catsou — la goutte d'eau qui a fait déborder le vase — qui a déclenché toute cette chaîne d'événements heureux"],answer:3,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"C'est Line elle-même qui décide d'aller présenter ses excuses à Charlotte, sans que personne ne le lui suggère.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Charlotte pratique la cyclodanse depuis son enfance, bien avant son accident.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Monsieur Briard est le père biologique de Charlotte.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"L'accident de Charlotte a été causé par un conducteur qui avait consommé de l'alcool.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Elle n'avait jamais baissé les bras. C'est une battante, tu sais. » — Que signifient ces expressions ?",options:["Baisser les bras = s'étirer ; être une battante = aimer la boxe","Baisser les bras = avoir froid ; être une battante = être agressive","Baisser les bras = abandonner, renoncer face aux difficultés ; être une battante = quelqu'un qui ne se décourage pas et continue malgré les obstacles","Baisser les bras = demander de l'aide ; être une battante = être très sportive"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Il dégageait des ondes de tristesse et de remords à 10 km à la ronde. » — Que signifie remords ?",options:["Une grande colère difficile à contrôler","Une profonde fatigue après une longue journée de travail","Un sentiment de culpabilité douloureux lié à quelque chose qu'on a fait de mal","Une envie irrésistible de recommencer quelque chose"],answer:2,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Je me suis dit que c'était du grand n'importe quoi, alors on les a barrées. » — Que signifie barrées ?",options:["Elles ont fermé la liste à clé pour que personne ne la lise","Elles ont rayé certaines hypothèses de la liste parce qu'elles semblaient trop absurdes","Elles ont rangé la liste dans un tiroir pour ne plus y penser","Elles ont encadré les meilleures idées pour les retenir"],answer:1,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Line apporte des macarons pour s'excuser. Monsieur Briard est la fille biologique de Charlotte. À la fin, Monsieur Briard offre à Line un chaton qu'elle appelle Droppy.","Résumé B : Line apporte des cookies pour s'excuser. Charlotte n'est pas la fille biologique de Monsieur Briard mais sa belle-fille. La brouille date de deux ans avant l'histoire.","Résumé C : Line retourne s'excuser avec des cookies. Monsieur Briard quitte la classe car Charlotte est sa belle-fille, brouillée depuis deux ans. Grâce à Line, ils se réconcilient. Monsieur Briard offre à Line un chaton qu'elle appelle Droppy, ce qui signifie « goutte d'eau » en anglais."],answer:2,points:1}
  ]},
  {id:"miss_tucson",title:"La terrible Miss Tucson",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Elisabeth se retrouve-t-elle chez sa tante Miss Tucson ?",options:["Elle a été renvoyée de son pensionnat","Sa mère est morte et son père, débordé, l'a placée chez sa tante plutôt que de l'envoyer à l'orphelinat","Elle a demandé elle-même à vivre chez sa tante pour fuir son père","Elle a été envoyée chez sa tante par l'école"],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Comment Elisabeth réussit-elle à entrer dans le bureau interdit de Miss Tucson ?",options:["Elle attend que Miss Tucson parte à Londres et force la serrure avec une épingle","Elle convainc Augustine la cuisière de lui prêter la clé","Elle subtilise la clé à Marie-Louise en l'envoyant chercher son journal à l'étage pour avoir le temps de la voler","Elle profite d'une porte laissée ouverte par inadvertance par une domestique"],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Quelle est la vraie raison des voyages mensuels de Miss Tucson à Londres ?",options:["Elle y retrouve un amant en secret","Elle y mène des affaires commerciales","Elle rend visite à des membres de sa famille","Elle travaille pour Scotland Yard et enquête sur des affaires criminelles, dont celle de Jack l'Éventreur"],answer:3,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Que se passe-t-il quand Miss Tucson aperçoit son mystérieux poursuivant dans l'escalier de Scotland Yard ?",options:["Elle appelle les policiers à l'aide et le fait arrêter immédiatement","Elle reconnaît Elisabeth et lui crie dessus sans la frapper","Elle le frappe violemment avec son parapluie avant de réaliser qu'il s'agit d'Elisabeth","Elle s'enfuit en courant et demande au lieutenant Ridge de l'intercepter"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Miss Tucson a-t-elle prétendu se fâcher avec la mère d'Elisabeth, Adélaïde, il y a plus de vingt ans ?",options:["Parce qu'Adélaïde avait épousé un homme que Miss Tucson n'aimait pas","Parce que Miss Tucson était jalouse du bonheur de sa sœur","Parce que Scotland Yard lui avait imposé de couper les liens familiaux pour des raisons de confidentialité liées à son travail d'enquêtrice secrète","Parce que les deux sœurs s'étaient disputées pour une question d'héritage familial"],answer:2,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Quand Marie-Louise dit à Elisabeth : « C'est Londres qui doit trembler en ce moment-même, pas Miss Tucson ! », que révèle-t-elle sans le vouloir ?",options:["Que Miss Tucson est une femme très courageuse qui n'a peur de rien","Que Miss Tucson est tellement riche et puissante que personne n'oserait l'attaquer","Que Miss Tucson est du côté des enquêteurs et que c'est elle qui fait peur aux criminels, pas l'inverse","Que Miss Tucson connaît personnellement Jack l'Éventreur et n'a donc rien à craindre de lui"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"À la fin du récit, Elisabeth demande si le lieutenant Ridge est « la différence entre le mariage et l'amour ». Que veut-elle dire ?",options:["Qu'elle pense que Ridge et Miss Tucson devraient se marier pour être heureux","Qu'elle ne comprend pas pourquoi Miss Tucson travaille avec Ridge plutôt qu'avec d'autres policiers","Qu'elle veut savoir si Ridge est un homme marié et donc indisponible pour Miss Tucson","Qu'elle a compris que Miss Tucson aime Ridge sans l'avoir épousé, ce qui explique son choix de rester célibataire"],answer:3,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, Miss Tucson dit à Elisabeth qu'elle est « à même de garder un secret » et lui fait un clin d'œil. Qu'est-ce que cela révèle sur l'évolution de leur relation ?",options:["Miss Tucson pense qu'Elisabeth est trop jeune pour comprendre les enjeux de son travail","Miss Tucson veut recruter Elisabeth comme apprentie enquêtrice dès son retour","Miss Tucson a appris à faire confiance à Elisabeth et la reconnaît désormais comme une égale digne de partager son secret","Miss Tucson veut s'assurer qu'Elisabeth se taira par peur des conséquences"],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Miss Tucson occupe un poste officiel et reconnu au sein de Scotland Yard.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Elisabeth réussit à lire des documents secrets dans le bureau de sa tante lors de son intrusion nocturne.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Miss Tucson est plus sévère avec Elisabeth depuis que cette dernière lui a répondu avec insolence à propos de son voyage à Londres.",answer:true,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"Elisabeth suit sa tante à Londres parce qu'elle veut l'empêcher de se rendre à la police, pensant qu'elle est Jack l'Éventreur.",answer:true,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Elle se sait sur le point d'exploser. » — Que signifie exploser ici ?",options:["Tomber malade à cause de sa colère trop longtemps retenue","S'enfuir en courant pour ne pas faire de bêtise","Ne plus pouvoir contenir sa colère et laisser éclater ses émotions","Crier si fort que tout le monde dans la maison l'entendrait"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Elle meurt d'envie de le découvrir au plus vite. » — Que signifie mourir d'envie ?",options:["Être tellement curieuse qu'elle risque de tomber malade","Avoir une envie si forte qu'elle est difficile à contenir","Vouloir quelque chose mais avoir trop peur pour le faire","Être prête à tout sacrifier pour obtenir ce qu'elle veut"],answer:1,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Tirant sur sa pipe avec flegme, il attend patiemment la suite des événements. » — Que signifie flegme ?",options:["Une grande impatience cachée derrière un air calme","Une mauvaise humeur que l'on essaie de dissimuler","Un manque total d'intérêt pour ce qui se passe autour de soi","Un calme tranquille et imperturbable, même dans les situations agitées"],answer:3,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Elisabeth pénètre dans le bureau de sa tante, mais doit fuir avant d'y découvrir quoi que ce soit. En accumulant les indices, elle finit par croire que sa tante est Jack l'Éventreur, la suit jusqu'à Scotland Yard et se fait frapper avec le parapluie. Miss Tucson lui révèle qu'elle est enquêtrice secrète et lui explique aussi qu'elle a dû se fâcher avec sa mère il y a vingt ans sur ordre de Scotland Yard. Les deux se réconcilient.","Résumé B : Elisabeth découvre des documents dans le bureau prouvant que sa tante travaille pour la police.","Résumé C : Miss Tucson la frappe avec son parapluie mais il n'est pas question de la brouille forcée avec la mère d'Elisabeth dans ce résumé."],answer:0,points:1}
  ]},
  {id:"ombre_lumiere",title:"L'ombre et la lumière",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Samira se retrouve-t-elle à donner la réplique à Laura lors de l'audition ?",options:["Elle s'est inscrite à l'audition sans le dire à Laura","Elle voulait impressionner Monsieur Lopez","Monsieur Léoton l'y oblige pour que Laura, la dernière de la liste, puisse passer","Laura lui avait demandé de se préparer à la remplacer"],answer:2,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Quel rôle Samira décroche-t-elle à l'issue de l'audition ?",options:["Arsinoé, l'antagoniste de la pièce","Un rôle secondaire dans la pièce de Molière","Célimène, le premier rôle féminin du Misanthrope","Accessoiriste et habilleuse pour la troupe"],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Que fait Laura après avoir appris qu'elle n'a pas obtenu le rôle de Célimène ?",options:["Elle félicite Samira et continue à assister aux répétitions","Elle cesse de parler à Samira et passe son temps avec une autre fille de la classe","Elle demande à Monsieur Lopez de refaire une audition","Elle quitte le collège pendant plusieurs semaines"],answer:1,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Samira ne peut-elle pas jouer lors de la représentation finale au départ ?",options:["Elle a trop le trac et refuse de monter sur scène","Laura lui a volé sa robe de Célimène avant le spectacle","Monsieur Lopez décide de donner le rôle à Laura à la dernière minute","Elle s'est blessée à la cheville en trébuchant sur un accessoire durant la dernière répétition"],answer:3,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Samira dit-elle à la fin qu'elle est « presque sûre que Laura n'est pas étrangère aux petits incidents » qui lui sont arrivés ?",options:["Laura lui a avoué qu'elle avait organisé tous les accidents","Samira est jalouse de Laura et invente des raisons de la soupçonner","Tiago confirme qu'il a abîmé la chaise sur demande de Laura, laissant penser qu'elle a aussi provoqué d'autres incidents","Monsieur Léoton a découvert que Laura sabotait les répétitions"],answer:2,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Quand Sohann dit à Samira : « Au théâtre, tu es juste Sam, pas 'la copine de Laura' », que veut-il lui faire comprendre ?",options:["Que Laura est une mauvaise amie dont il faut se méfier","Que Samira devrait changer de groupe d'amis","Que le théâtre lui permet de découvrir qui elle est vraiment, en dehors de l'ombre de Laura","Que les autres élèves ne savent pas que Samira et Laura sont amies"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Samira pleure-t-elle dans les coulisses après être tombée de la chaise ?",options:["Parce qu'elle s'est fait très mal et que la douleur est insupportable","Parce qu'elle a honte d'être maladroite devant toute la troupe","Parce qu'elle croit que Laura va reprendre son rôle et qu'elle va perdre à la fois le théâtre et son amie","Parce que Tiago s'est moqué d'elle avec les autres acteurs"],answer:2,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin de la représentation, Samira demande au public d'applaudir Laura. Qu'est-ce que ce geste révèle sur elle ?",options:["Qu'elle veut montrer à tout le collège qu'elle a pardonné à Laura","Qu'elle pense que Laura méritait davantage le rôle de Célimène","Qu'elle veut se faire bien voir des professeurs en montrant qu'elle est généreuse","Qu'elle a grandi et qu'elle est capable de mettre leur amitié avant sa fierté personnelle"],answer:3,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Tiago accueille chaleureusement Samira dans la troupe dès la première répétition.",answer:true,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Laura rejoint la troupe de théâtre comme accessoiriste parce qu'elle le demande elle-même.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Samira connaît son texte par cœur bien avant la représentation finale.",answer:true,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"C'est Samira elle-même qui décide de retourner jouer malgré sa cheville blessée.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Elle s'avance sur la scène avec aplomb. » — Que signifie aplomb ?",options:["Une grande timidité difficile à surmonter","Une tenue de costume particulière pour le théâtre","Une assurance calme, un air confiant et décidé","Une grande agitation et beaucoup de nervosité"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Monsieur Lopez et Madame Medjouel font office de jury. » — Que signifie jury ?",options:["Un groupe de spectateurs venus regarder le spectacle","Un groupe de personnes chargées d'évaluer et de prendre une décision","Un groupe d'élèves qui préparent la pièce ensemble","Un comité qui s'occupe de la décoration de la scène"],answer:1,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Quelques élèves ricannent dans le fond de la pièce. » — Que signifie ricannent ?",options:["Chantent doucement pour se calmer","Parlent à voix haute sans écouter le professeur","Pleurent discrètement parce qu'ils sont déçus","Rient de façon moqueuse et un peu méchante"],answer:3,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Lors de la dernière répétition, Samira se blesse et Laura joue à sa place pour la représentation finale. Samira monte quand même sur scène à la fin pour saluer et demande au public d'applaudir Laura.","Résumé B : Laura joue pendant toute la représentation finale. À la fin, Samira monte sur scène et demande au public d'applaudir Laura, ce qui les réconcilie.","Résumé C : Samira se blesse à la cheville. Son frère Driss et Laura la convainquent de jouer quand même. Elle monte sur scène malgré sa blessure, la représentation est un succès et elle demande au public d'applaudir Laura, ce qui les réconcilie."],answer:2,points:1}
  ]},
  {id:"bug_mamie",title:"Le bug de Mamie Henriette",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Où se trouve Bastien au début de l'histoire ?",options:["Dans le cabanon de son grand-père","Sur la tombe de son grand-père","Dans la cuisine de sa grand-mère","Chez le voisin Jo"],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Comment Papy Fernand est-il décédé ?",options:["D'un accident de vélo","D'une longue maladie","D'un infarctus du myocarde","Il s'est noyé dans la rivière"],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Que fait Bastien dans un moment de colère dans le cabanon ?",options:["Il casse l'établi de son grand-père","Il tire à la carabine sur un corbeau, détruisant accidentellement la tête de l'épouvantail","Il brise le moulin à vent","Il lance des outils par la fenêtre"],answer:1,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Comment Bastien parvient-il à sortir du cabanon où Henriette l'a enfermé ?",options:["Il casse la fenêtre","Il sonne à l'aide avec le téléphone de Papy","Il souffle dans la corne de brume, et c'est Nelson qui vient l'ouvrir","Il enfonce la porte à coups de pied"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Bastien ne veut-il pas appeler ses parents pour leur parler du comportement de Mamie Henriette ?",options:["Parce qu'il n'a pas de téléphone","Parce qu'il pense qu'ils ne le croiraient pas et qu'il devrait aussi avouer sa propre faute avec la carabine","Parce qu'ils sont en voyage à l'étranger","Parce qu'il a peur qu'ils lui interdisent de revenir à Fontagnac"],answer:1,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi le village semble-t-il « avoir perdu son âme » après la mort de Fernand ?",options:["Parce que les habitants ont déménagé","Parce que tous les commerces sont fermés","Parce que Fernand était le cœur du village et que sa mort plonge tout le monde dans la tristesse","Parce qu'une tempête a tout détruit"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Que révèle le comportement de Bastien (nettoyer la voiture, rentrer les moutons, réparer les jardinières) sur son caractère ?",options:["Il est obéissant parce qu'il a peur de sa grand-mère","Il est responsable et cherche à réparer le tort causé, même si ce n'est pas entièrement sa faute","Il veut se faire remarquer par les villageois","Il le fait uniquement pour éviter les ennuis avec ses parents"],answer:1,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Mamie Henriette sourit-elle quand Bastien la sermonne et lui dit qu'il a honte d'elle ?",options:["Parce qu'elle se moque de lui","Parce que son plan a fonctionné : Bastien exprime enfin sa peine et sort de sa colère","Parce qu'elle est vraiment devenue folle","Parce qu'elle est fière de ses bêtises"],answer:1,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Justin est le nom d'un camarade de classe de Bastien.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"C'est Nelson qui convainc finalement Henriette de poser la carabine en disant que le dindon n'est pas méchant.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Mamie Henriette avait réellement perdu la tête et tout organisé seule.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"L'eau rouge de la fontaine contenait du poison.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Bastien ressassait l'enterrement de la veille. » — Que signifie ressassait ?",options:["Oubliait rapidement","Repassait sans cesse dans sa tête","Racontait à voix haute","Dessinait mentalement"],answer:1,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Le jeune garçon revoyait la cérémonie funèbre. » — Que signifie funèbre ?",options:["Joyeuse et colorée","Secrète et mystérieuse","Liée à un enterrement, à la mort","Organisée en plein air"],answer:2,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Henriette n'eut pas du tout la réaction escomptée. » — Que signifie escomptée ?",options:["Espérée et prévue","Violente et imprévisible","Lente et hésitante","Exagérée et théâtrale"],answer:0,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Bastien est en vacances chez ses grands-parents après la mort de Papy Fernand. Il tire sur un corbeau et détruit accidentellement l'épouvantail Justin. Sa grand-mère Henriette sème le chaos dans le village. Bastien répare les dégâts et apprend que tout était une mise en scène organisée avec les villageois pour l'aider à surmonter sa colère et son deuil.","Résumé B : Bastien tire sur un corbeau et blesse accidentellement Nelson. Henriette sème le chaos. Bastien répare les dégâts avant d'apprendre que tout était une mise en scène.","Résumé C : Henriette, furieuse contre son petit-fils, organise seule une série de bêtises dans le village pour lui donner une leçon. Bastien répare tous les dégâts et se réconcilie avec sa grand-mère."],answer:0,points:1}
  ]},
  {id:"echappee_belle",title:"L'échappée belle",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Quel est le prénom de la narratrice ?",options:["Léa","Emma","Lucie","Clara"],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Quel âge a Emma au moment de l'histoire ?",options:["11 ans","10 ans","12 ans","13 ans"],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Comment s'appelle le cheval qu'Emma décide de libérer ?",options:["Éclair","Tornado","Comète","Fusée"],answer:2,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Où Emma et son grand-père amènent-ils Comète ?",options:["Dans une ferme près de Nangis","Dans un haras en Normandie","En Camargue, aux Saintes-Maries-de-la-Mer","Dans les Alpes"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Emma décide-t-elle de libérer Comète dès le spectacle ?",options:["Elle veut se venger du dresseur qui lui a été impoli","Elle a vu la souffrance du cheval dans ses yeux et a compris qu'il était maltraité","Elle veut offrir un cheval à son grand-père","Elle est jalouse des autres enfants qui peuvent monter à cheval"],answer:1,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Antoine tend-il ses bracelets lumineux à Emma avant qu'elle parte ?",options:["Il n'en veut plus car ils sont cassés","C'est un cadeau d'anniversaire","Il veut l'aider à se guider dans la nuit","Il les échange contre la promesse qu'elle lui rapporte un souvenir"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Quand le gardian retire son chapeau et que leurs regards se croisent, Emma s'évanouit. Pourquoi ?",options:["Elle a trop chaud et n'a pas dormi","Elle a peur des chevaux camarguais","Elle réalise que le gardian est son père qu'elle n'a pas revu depuis des années","Elle apprend que Comète est gravement malade"],answer:2,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, le grand-père décide de rester en Camargue. Qu'est-ce que cela révèle sur lui ?",options:["Il est en mauvaise santé et a besoin d'air marin","Il veut surveiller le père d'Emma","La vie à la maison de retraite ne lui convenait pas et cette aventure lui a redonné goût à la vie","Il veut apprendre à être gardian"],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Emma vit avec son père, sa mère et son petit frère Antoine.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"C'est le grand-père d'Emma qui a eu l'idée d'aller en Camargue pour libérer Comète.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Comète est en réalité une jument et elle attend un poulain.",answer:true,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"Le grand-père a obtenu la maison de gardian en la payant de sa poche.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« On voit apparaître ses côtes saillantes sur son flanc. » — Que signifie saillantes ?",options:["Cachées sous le pelage","Très colorées et visibles","Qui ressortent de manière visible, qui dépassent","Solides et bien formées"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Je baragouine un truc en rapport avec le cirque. » — Que signifie baragouine ?",options:["Elle explique clairement et précisément","Elle ment délibérément et calmement","Elle dit quelque chose de confus et peu compréhensible","Elle chante pour se donner une contenance"],answer:2,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Comète commence à s'agiter dans le van. Il trépigne d'impatience. » — Que signifie trépigne ?",options:["Il se couche et s'endort","Il s'agite en frappant le sol, tellement il est impatient","Il hennit très fort pour appeler ses congénères","Il recule de peur dans un coin"],answer:1,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Emma, 12 ans, va au cirque avec sa famille et découvre les mauvaises conditions de vie des animaux. Elle décide de libérer Comète. La nuit venue, elle s'échappe avec l'aide de son grand-père et tous deux rejoignent la Camargue en van. Là-bas, Emma retrouve son père, un gardian, et apprend que Comète est une jument attendant un poulain. Après la naissance de Bingo, Emma repart avec sa famille, laissant Comète et son grand-père en Camargue.","Résumé B : Emma, 11 ans, prend le train en Camargue avec Antoine. Comète met bas un poulain que le père appelle Bingo. Emma repart avec sa mère après avoir réconcilié ses deux parents.","Résumé C : Le père d'Emma est vétérinaire en Camargue. Une vétérinaire extérieure aide Comète à mettre bas. Emma repart avec sa mère."],answer:0,points:1}
  ]},
  {id:"gardienne_eaux",title:"La gardienne des eaux vives",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Quel est le prénom de la narratrice ?",options:["Fanny","Assia","Faustine","Moira"],answer:2,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi le père de Faustine déménageait-il régulièrement ?",options:["Il cherchait l'inspiration pour ses romans","Il changeait souvent de travail","Il voulait cacher et protéger Faustine des hommes-chauves-souris","Il aimait les voyages et les découvertes"],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Qu'est-ce qu'un « cristal » dans ce récit ?",options:["Un objet magique que les prêtresses portent autour du cou","Une arme utilisée contre les hommes noirs","Le nom du temple secret des gardiennes","Un arrêt du temps qui permet d'accéder à un autre monde"],answer:3,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Où se trouve le temple des gardiennes des eaux vives ?",options:["Dans une forêt à la périphérie de la ville","Sous la cathédrale, dans des souterrains","Dans un jardin secret caché derrière des grilles près de la cathédrale de Chartres","Dans une ruine à l'extérieur de la ville"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi le père de Faustine lui a-t-il caché que sa mère était vivante ?",options:["Il était jaloux de Moira et ne voulait pas qu'elles se rencontrent","Moira lui avait interdit d'en parler","Il voulait protéger Faustine de la douleur et du danger lié à sa destinée","Il ignorait lui-même que Moira était encore en vie"],answer:2,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Faustine accepte-t-elle de devenir gardienne des eaux vives ?",options:["Par obéissance envers sa mère Moira","Pour se rapprocher de son père qui habite près du temple","Par peur des hommes-chauves-souris","Par désir de vivre une destinée extraordinaire et hors du commun"],answer:3,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Que révèle la relation entre Faustine et Vivian sur leur situation respective ?",options:["Ils sont ennemis et se battent constamment","Vivian espionne Faustine pour son père Helios","Tous deux rejettent la guerre que mènent leurs clans respectifs et cherchent la paix","Faustine utilise Vivian pour obtenir des informations sur les hommes noirs"],answer:2,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin du récit, Faustine dit qu'elle n'abandonnera pas son enfant. Qu'est-ce que cela révèle ?",options:["Elle critique son père qui l'a mal élevée","Elle veut quitter le temple pour vivre une vie normale","Elle a compris et pardonné les choix de sa mère, mais refuse de reproduire la même erreur","Elle veut se venger de Moira en lui montrant qu'elle sera une meilleure mère"],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Faustine avait de nombreux amis avant de rencontrer Fanny, car elle avait beaucoup voyagé.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Les eaux vives donnent l'immortalité à ceux qui s'y baignent.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"C'est Yasmine qui a trahi les gardiennes en ouvrant la grille du parc à l'ennemi.",answer:true,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"Le père de Faustine est un homme ordinaire, sans pouvoirs magiques.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« À mes interrogations, il répondait, le regard fuyant. » — Que signifie regard fuyant ?",options:["Un regard vif et joyeux","Un regard fixe et assuré","Un regard qui évite celui de l'autre, qui cherche à ne pas croiser les yeux","Un regard triste et plein de larmes"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« papa tenta alors de m'amadouer : Tu as carte blanche pour ta chambre. » — Que signifie amadouer ?",options:["Gronder quelqu'un pour le faire obéir","Ignorer quelqu'un pour le punir","Expliquer clairement une situation difficile","Calmer quelqu'un de mécontent en étant gentil et en lui faisant plaisir"],answer:3,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« ces épreuves m'apparurent insurmontables, car ma constitution fragile m'avait tenue écartée des disciplines sportives. » — Que signifie insurmontables ?",options:["Très ennuyeuses et sans intérêt","Faciles à réaliser avec un peu d'entraînement","Impossibles à surmonter, trop difficiles pour être réussies","Dangereuses et réservées aux adultes"],answer:2,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Faustine, une jeune fille surprotégée par son père, découvre lors d'une sortie que des hommes-chauves-souris la recherchent. Des femmes-panthères la sauvent et lui révèlent qu'elle est destinée à devenir gardienne des eaux vives, comme sa mère Moira qu'elle croyait morte. Elle rejoint le temple, participe au combat final. Ses deux parents meurent lors de la bataille. Faustine devient grande prêtresse et attend un enfant de Vivian, qu'elle promet de ne pas abandonner.","Résumé B : Faustine apprend à se transformer en panthère. Lors du combat final, son père fait exploser le temple pour protéger la source. Faustine devient grande prêtresse mais le résumé omet Vivian, père de l'enfant.","Résumé C : Faustine appelle les gargouilles à la rescousse et remporte la victoire. Ses parents survivent à la bataille et restent vivre au temple avec elle."],answer:0,points:1}
  ]},
  {id:"journal_secret",title:"Le journal secret",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Où Lucie trouve-t-elle le cahier ?",options:["Dans sa salle de classe","Sur un banc dans le parc","Dans la bibliothèque de l'école","Chez sa meilleure amie Marguerite"],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Comment Lucie et Marguerite cherchent-elles à identifier l'auteur du journal en classe ?",options:["En demandant aux élèves d'écrire leur nom sur une feuille","En comparant l'écriture du journal avec celle des rédactions distribuées en cours","En posant directement des questions aux garçons de la classe B","En regardant les photos de classe affichées dans le couloir"],answer:1,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Quels indices du journal permettent aux deux amies de localiser le « coin secret » ?",options:["Une description de la rivière et d'un pont en pierre","La mention d'une vieille sucrerie, d'une église Saint-Fiacre et d'avions qui décollent","Une carte dessinée à la main dans le cahier","La description d'un champ de tournesols près de l'école"],answer:1,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Qui est finalement le véritable auteur du journal secret ?",options:["Un élève timide de la classe B nommé Aurélien","Le sous-directeur de l'école","Jean-Claude Sirop, un écrivain venu rendre visite à la classe","Le professeur de mathématiques, M. Lorient"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Lucie s'échappe-t-elle dans le parc au début de l'histoire ?",options:["Parce qu'elle a rendez-vous avec Marguerite","Parce qu'elle veut éviter les questions de sa mère, notamment celle sur l'ordre de sa chambre","Parce qu'elle doit remettre un devoir en retard à son professeur","Parce qu'elle cherche un endroit calme pour étudier le Roi-Soleil"],answer:1,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Lucie et Marguerite inventent-elles une histoire de concours de chocolat auprès de Clara ?",options:["Parce qu'elles veulent organiser une vraie fête à l'école","Parce qu'elles savent que Clara est gourmande et bavarde, et qu'elle leur donnera facilement des informations sur les garçons","Parce qu'elles veulent faire une blague à leur professeure","Parce qu'elles veulent gagner du chocolat pour elles-mêmes"],answer:1,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Que révèle la façon dont Lucie et Marguerite traitent les copies lors de la distribution en classe ?",options:["Elles sont impolies avec tout le monde sans raison","Elles accordent plus d'attention aux copies des garçons car elles y cherchent l'écriture du journal","Elles veulent terminer la distribution le plus vite possible pour aller jouer","Elles détestent les filles de leur classe"],answer:1,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi l'auteur du journal n'avait-il pas écrit son vrai nom dedans ?",options:["Parce qu'il avait oublié de le faire","Parce que c'était un brouillon et non un vrai journal","Parce qu'il s'agissait d'un roman fictif écrit à la première personne, sous la forme d'un journal intime","Parce qu'il voulait que quelqu'un le retrouve et cherche à le lui rendre"],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Lucie lit immédiatement le journal en entier dès qu'elle le trouve sur le banc.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Les deux amies retournent deux jours de suite au « coin secret » pour attendre le propriétaire du journal.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"L'écriture du journal permet aux deux amies d'identifier formellement son auteur.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"L'écrivain Jean-Claude Sirop habitait dans la région et s'était inspiré des paysages locaux.",answer:true,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« La question-massue qui l'anéantit. » — Que signifie anéantit ?",options:["La remplit de joie","L'écrase complètement, la décourage totalement","L'oblige à répondre poliment","La fait rire malgré elle"],answer:1,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Madame Pinson a fait remarquer sèchement à Marguerite. » — Que signifie sèchement ?",options:["D'une voix douce et bienveillante","D'un ton brusque et sans gentillesse","À voix basse, pour ne pas être entendue","Avec beaucoup d'humour"],answer:1,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« L'étau se resserre. Aurélien reste le seul candidat possible. » — Que signifie l'étau se resserre ?",options:["Les deux amies abandonnent leurs recherches","Le cercle des suspects s'élargit","Le nombre de possibilités diminue, on se rapproche de la réponse","Les deux amies commencent à se disputer"],answer:2,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Lucie trouve un journal intime sur un banc du parc. Avec son amie Marguerite, elle tente de retrouver son propriétaire grâce à plusieurs indices. Toutes leurs pistes échouent, jusqu'au jour où un écrivain vient rendre visite à leur classe et révèle qu'il a perdu le brouillon de son roman, rédigé sous forme de journal intime.","Résumé B : Elles identifient rapidement l'auteur grâce à la comparaison des écritures lors de la distribution des rédactions. Il s'agit d'Aurélien, un garçon de la classe B. Elles lui rendent le cahier à la fin de l'histoire.","Résumé C : Elles retrouvent le « coin secret » décrit dans le journal et y attendent le garçon, qui finit par venir le lendemain et reconnaît son cahier. Les deux amies lui avouent l'avoir lu."],answer:0,points:1}
  ]},
  {id:"fil_bleu",title:"Le fil bleu",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Que fait Dorian avec Max dans l'escalier ?",options:["Il le met dans son sac à dos.","Il le pose par terre et l'encourage à monter les marches.","Il le donne à Gabrielle pour qu'elle le tienne.","Il le cache dans sa poche dès le départ."],answer:1,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Que découvrent les jumeaux en entrant dans la chambre de Babou ?",options:["Babou est endormie dans son lit.","Babou a disparu et l'appartement est vide.","Babou est assise sur une chaise, les mains ligotées, les yeux bandés et la bouche couverte de ruban adhésif.","Babou discute avec monsieur Julien."],answer:2,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Qu'est-ce que Max rapporte lors de sa deuxième fouille, devant l'appartement de madame Jansen ?",options:["Un bouton arraché d'un manteau.","Un bout de fil bleu.","Une clé de l'appartement.","Rien du tout."],answer:1,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi madame Jansen avait-elle volé les bijoux de Babou ?",options:["Elle voulait les offrir à sa famille.","Elle n'avait plus payé son loyer depuis longtemps et avait besoin d'argent pour s'enfuir.","Elle était jalouse des bijoux de Babou.","Elle voulait se venger de Babou."],answer:1,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi monsieur Julien ne voulait-il pas appeler la police lorsqu'il a entendu des bruits suspects ?",options:["Il pensait que ce n'était pas grave et qu'il valait mieux attendre.","Il voulait garder les bijoux pour lui.","Il soupçonnait sa petite-fille Zoé et ne voulait pas qu'elle ait des ennuis.","Il avait peur de la police à cause de son passé en prison."],answer:2,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Dorian fait-il faire des tours à Max devant Zoé ?",options:["Il veut montrer que Max est un rat apprivoisé et inoffensif.","Il veut distraire Zoé pour que Gabrielle puisse fouiller son sac.","Il veut que Zoé adopte un rat comme animal de compagnie.","Il s'ennuie et cherche à passer le temps."],answer:1,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi madame Jansen utilisait-elle un déambulateur alors qu'elle pouvait très bien marcher et courir ?",options:["Elle voulait faire pitié à son propriétaire pour qu'il ne la mette pas à la porte.","Elle avait eu un accident et devait se rééduquer.","Elle voulait que les autres habitants lui rendent des services.","C'était une habitude qu'elle avait prise en vieillissant."],answer:0,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"Lorsque Babou dit à madame Jansen de prendre les bijoux et de disparaître, que cherche-t-elle vraiment à faire ?",options:["Elle abandonne et accepte de perdre ses bijoux.","Elle essaie de faire fuir madame Jansen pour qu'elle libère Gabrielle, sachant que la police est en route.","Elle veut éviter une bagarre et pense que les bijoux ne sont pas importants.","Elle a peur de madame Jansen et obéit par terreur."],answer:1,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Gabrielle et Dorian sont des jumeaux qui se ressemblent physiquement.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"C'est Max qui permet aux jumeaux de découvrir que la véritable voleuse est madame Jansen, en rapportant un fil bleu de son appartement.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Les boucles d'oreilles de Babou sont retrouvées dans le magasin d'occasion, encore en vitrine.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"Babou a du mal à sortir de chez elle après l'agression parce qu'elle a peur.",answer:true,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Il lâche : Enfin, vous voilà ! » — Le mot lâche signifie ici :",options:["abandonne, jette quelque chose par terre","dit, prononce (une parole)","libère un animal","hésite avant de parler"],answer:1,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Certains bijoux sont ornés de diamants. » — Le mot ornés signifie :",options:["fabriqués entièrement en diamants","décorés, agrémentés de","volés puis recouverts de","cachés sous"],answer:1,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Flagrant délit de recel. » — Le mot recel désigne :",options:["le fait de cacher des personnes recherchées par la police","le fait d'acheter, de garder ou de vendre des objets dont on sait qu'ils ont été volés","le fait de voler directement dans une maison","le fait de mentir à la police lors d'une enquête"],answer:1,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Gabrielle et Dorian trouvent Babou ligotée dans sa chambre. Avec l'aide de leur rat Max, les jumeaux mènent l'enquête et découvrent les boucles d'oreilles de Babou dans un magasin d'occasion. Ils surprennent madame Jansen qui tente de fuir avec les bijoux. Babou appelle la police, qui arrête madame Jansen devant l'immeuble.","Résumé B : Max retrouve les bijoux cachés dans l'armoire de madame Jansen. La police arrête madame Jansen alors qu'elle tentait de prendre le train.","Résumé C : C'est Zoé, la petite-fille de monsieur Julien, que la police arrête : elle avait fait un double des clés pour entrer chez Babou."],answer:0,points:1}
  ]},
  {id:"princesse_moche",title:"La légende de la princesse moche",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Comment s'appelle la princesse de cette histoire ?",options:["Séraphine","Fanny","Marjolaine","Euclave"],answer:2,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Marjolaine doit-elle se marier ?",options:["Elle est amoureuse et veut fonder une famille","Le roi a perdu un pari et doit donner sa fille en mariage","Elle veut quitter le château pour voir du pays","La tradition exige qu'elle trouve un mari avant de devenir reine"],answer:3,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Qui est Séraphin ?",options:["Un prince venu d'un pays lointain","Le cousin du duc de Gondard","Un jeune paysan que Marjolaine rencontre au bord d'un lac","Un chevalier de la garde royale"],answer:2,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Marjolaine se coupe-t-elle les cheveux ?",options:["Elle veut suivre une nouvelle mode lancée par la reine","Elle punit une servante qui l'a trahie","Elle veut ressembler à une princesse d'un autre royaume","Elle se déguise en homme pour aller combattre à la place de Séraphin lors du duel"],answer:3,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Marjolaine repoussait-elle tous les prétendants avant de rencontrer Séraphin ?",options:["Elle était trop timide pour parler aux princes","Ses parents lui interdisaient de choisir elle-même","Elle ne trouvait aucun prince intéressant et attendait quelqu'un qui lui ressemble vraiment","Elle avait peur de quitter le château"],answer:2,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Que révèle la rencontre avec Séraphin au bord du lac sur le caractère de Marjolaine ?",options:["Qu'elle est naïve et se laisse facilement tromper","Qu'elle est capricieuse et veut humilier les paysans","Qu'elle est directe, honnête, et capable d'apprécier quelqu'un au-delà des apparences et des conventions","Qu'elle est trop orgueilleuse pour admettre qu'elle est moche"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi le peuple et les nobles changent-ils d'avis sur Séraphin après le duel ?",options:["Ils découvrent qu'il est en réalité d'origine noble","Le roi ordonne à tous de l'accepter comme futur roi","Marjolaine leur explique les vraies qualités de Séraphin","Sa victoire inattendue contre Gondard lui donne une image de courage et de force qui convainc le peuple"],answer:3,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, le mariage a lieu sur un rocher en pleine nature, loin du château. Qu'est-ce que cela symbolise ?",options:["Marjolaine veut punir les nobles qui se sont moqués d'elle","Le château a été détruit pendant le duel","Marjolaine et Séraphin rejettent les conventions et choisissent l'amour vrai au-delà des traditions","Le roi n'avait plus assez d'argent pour organiser un grand bal"],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"C'est Marjolaine elle-même qui a décidé de fuir le château après avoir surpris la conversation de ses parents.",answer:true,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Le duc de Gondard est un ennemi de longue date du père de Marjolaine.",answer:false,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Séraphin gagne le duel contre Gondard et lui laisse ensuite la vie sauve.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"Lors du mariage, c'est Séraphin qui porte des habits simples et Marjolaine qui est habillée de façon somptueuse.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« le père de Marjolaine faisait donner des bals somptueux » — Que signifie somptueux ?",options:["Secrets et réservés aux nobles","Ennuyeux et trop longs","D'une grande richesse et d'un grand luxe","Organisés très rapidement et sans préparation"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« une chose fut dite, en chuchotant, par un prince éconduit. » — Que signifie éconduit ?",options:["Un prince qui a accepté d'épouser Marjolaine","Un prince qui a été rejeté et renvoyé","Un prince qui s'est battu en duel pour conquérir la princesse","Un prince qui est arrivé en carrosse"],answer:1,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Sournoisement, la rumeur enflait. » — Que signifie enflait ?",options:["La rumeur disparaissait peu à peu","La rumeur était inventée de toutes pièces","La rumeur grossissait et se répandait de plus en plus","La rumeur était confirmée par le roi"],answer:2,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Marjolaine, une princesse qu'on dit moche, peine à trouver un mari car elle refuse tous les prétendants. Elle rencontre Séraphin, un jeune paysan. Quand le duc de Gondard défie Séraphin en duel, Marjolaine se déguise en homme, le fait emprisonner et combat à sa place. Elle gagne le duel. Le mariage a lieu sur un rocher en pleine nature, loin des fastes royaux.","Résumé B : Séraphin affronte le duc de Gondard en duel et le blesse grièvement. Grâce à sa victoire, il est accepté par le peuple et les nobles. Le mariage a lieu dans le château royal en grande pompe.","Résumé C : Marjolaine emprisonne Gondard pour l'empêcher de se battre, et Séraphin remporte le duel grâce à ses talents de combattant. Le mariage a lieu loin du château, sur un rocher."],answer:0,points:1}
  ]},
  {id:"resistance_enfants",title:"La résistance des enfants",series:"Récits Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Comment s'appelle le narrateur de cette histoire, devenu roi ?",options:["Luigi","Tito","Picolino","Korog"],answer:2,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Quel était le métier de Picolino avant de devenir roi ?",options:["Pêcheur","Boulanger","Forgeron","Berger"],answer:3,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Quel est le pouvoir magique de Mostar qui soumet les adultes de l'île ?",options:["Un poison versé dans l'eau du village","Un drapeau noir qui hypnotise ceux qui le regardent","Un charme d'endormissement qui prive les adultes de tout sentiment et de leur volonté","Une tempête magique qui enferme les habitants dans leurs maisons"],answer:2,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Quel instrument de musique Picolino utilise-t-il pour libérer les adultes ?",options:["Une flûte","Un tambourin","Un violon","Une mandoline"],answer:3,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi les enfants sont-ils les seuls à pouvoir résister au charme de Mostar ?",options:["Ils ont bu une potion magique préparée par Picolino","Ils se cachaient dans la grotte au moment de l'invasion","Le charme n'a aucun effet sur les plus jeunes, que les brigands jugent sans danger","Ils portent tous une marque de naissance qui les protège"],answer:2,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Korog, le brigand, aide-t-il Picolino à s'échapper plutôt que de le capturer ?",options:["Il veut trahir Mostar pour prendre sa place sur le trône","Il a pitié de Picolino car il est très jeune","Picolino lui a promis une partie de l'or de la mine","Il reconnaît sur Picolino la même marque de naissance que la sienne, signe qu'ils appartiennent au même peuple"],answer:3,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, Picolino avoue un secret qu'il a longtemps caché. En quoi ce secret est-il douloureux pour lui ?",options:["Il révèle qu'il n'a jamais vraiment aimé Toscana","Il admet que c'est Tito, et non lui, qui a eu l'idée de l'orchestre","Il confesse que son véritable père est Korog, un brigand ennemi, ce qui lui semble indigne de sa fonction de roi","Il avoue qu'il a utilisé sa magie pour devenir roi sans l'accord du peuple"],answer:2,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la toute fin, Toscana révèle que Luigi porte la même marque de naissance que Picolino. Qu'est-ce que cela laisse présager ?",options:["Luigi devra quitter l'île pour rejoindre le peuple de Korog","Luigi est en réalité le fils de Mostar","Luigi sera le prochain à trahir les siens comme Mostar","Luigi possède lui aussi un pouvoir magique, et son avenir sera extraordinaire mais incertain"],answer:3,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Picolino a toujours aimé l'île et ses habitants depuis son enfance.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Pendant que les adultes sont sous le charme, les enfants s'organisent seuls pour survivre et se répartissent des tâches précises.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"Picolino parvient à libérer ses parents adoptifs dès sa première visite à la mine, en leur parlant avec douceur.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"À la fin du combat, les brigands sont tous tués par la magie de la mandoline de Picolino.",answer:false,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« Garçon insoumis et belliqueux, je refusais de me laisser apprivoiser. » — Que signifie belliqueux ?",options:["Timide et renfermé sur lui-même","Curieux et avide d'apprendre","Agressif, toujours prêt à se battre et à provoquer les autres","Triste et mélancolique"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Le bavardage des deux hommes m'avait galvanisé. » — Que signifie galvanisé ?",options:["Effrayé et paralysé par la peur","Mis en colère et rendu violent","Convaincu de fuir le plus loin possible","Stimulé, rempli d'énergie et de motivation pour agir"],answer:3,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Mon plan était insensé, saugrenu, peut-être irréalisable. » — Que signifie saugrenu ?",options:["Dangereux et risqué pour tout le monde","Brillant et admiré de tous","Triste et sans espoir","Bizarre, absurde, qui paraît complètement ridicule au premier abord"],answer:3,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Picolino, un berger orphelin devenu roi, raconte comment il a libéré son île envahie par le tyran Mostar. Seuls les enfants résistèrent au charme. Picolino organise un orchestre avec les enfants. Leur musique brise le charme et chasse les envahisseurs sans violence. À la fin, Picolino avoue que Korog est son véritable père, et Toscana révèle que leur petit-fils Luigi porte aussi la marque magique.","Résumé B : Picolino était pêcheur, pas berger. Les enfants fabriquèrent des armes pour combattre les brigands. Picolino est le fils du roi Livio.","Résumé C : Picolino propose de combattre avec une armée de soldats recrutés dans les îles voisines. Ils remportent la victoire grâce à ce renfort extérieur."],answer:0,points:1}
  ]},
  {id:"renne_sabots",title:"Le renne aux sabots d'or",series:"Récit Express",totalPoints:16,questions:[
    {id:"q1",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Alexis accepte-t-il finalement d'aller en Laponie ?",options:["Il veut rencontrer le père Noël","Il est passionné par les rennes et la nature","Il est attiré par la promesse de conduire une motoneige","Il veut retrouver son oncle Nils qu'il connaît bien"],answer:2,points:1},
    {id:"q2",section:"Compréhension (QCM)",type:"mcq",text:"Comment s'appelle le berger de l'oncle Nils ?",options:["Arthur","Ensio","Rovaniemi","Sami"],answer:1,points:1},
    {id:"q3",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi le petit renne n'a-t-il pas de marque aux oreilles ?",options:["Les voleurs ont effacé la marque","Nils a oublié de le marquer","Il appartient à un autre éleveur","C'est un renne sauvage, il n'a pas de propriétaire"],answer:3,points:1},
    {id:"q4",section:"Compréhension (QCM)",type:"mcq",text:"Comment les voleurs avaient-ils obtenu les clés du hangar du père Noël ?",options:["Ils les avaient forcées avec un outil","Ils les avaient trouvées dans le gumpi","Ils les avaient subtilisées quand ils travaillaient comme saisonniers au village","Meri les leur avait données sans le savoir"],answer:2,points:1},
    {id:"q5",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Nils invite-t-il spécifiquement Alexis à venir en Laponie cette année-là ?",options:["Il est malade et a besoin d'aide pour son élevage","Il veut que sa famille lui rende visite avant sa mort","Il sait que le renne aux sabots d'or va apparaître et que leur famille est la seule à déchiffrer son langage","Il veut lui apprendre à conduire la motoneige"],answer:2,points:1},
    {id:"q6",section:"Compréhension (QCM)",type:"mcq",text:"Quand Alexis libère le renne plutôt que de le garder pour trouver la mine d'or, cela montre surtout qu'il…",options:["A peur des conséquences légales","Ne croit pas vraiment à l'existence de la mine","Préfère protéger la nature et l'animal plutôt que de s'enrichir","Obéit aux ordres de Meri"],answer:2,points:1},
    {id:"q7",section:"Compréhension (QCM)",type:"mcq",text:"Pourquoi Nils sort-il secrètement en pleine nuit et revient essoufflé ?",options:["Il est allé surveiller les rennes dans la toundra","Il a eu peur pour Alexis et cherchait de l'aide","Il était allé prévenir la police des voleurs","Il était allé chercher la pépite d'or dans sa cachette secrète pour l'offrir à Alexis"],answer:3,points:1},
    {id:"q8",section:"Compréhension (QCM)",type:"mcq",text:"À la fin, quand Alexis dit au garçonnet que « les légendes sont vraies », il pense surtout à…",options:["La magie des aurores boréales","L'existence des mines d'or en Laponie","Ses propres aventures avec le renne aux sabots d'or, qui ont confirmé la légende","La gentillesse de l'oncle Nils"],answer:2,points:1},
    {id:"q9",section:"Vrai ou Faux",type:"tf",text:"Alexis parle finlandais grâce aux cours qu'il a suivis à l'école.",answer:false,points:1},
    {id:"q10",section:"Vrai ou Faux",type:"tf",text:"Meri propose d'attacher le renne à un arbre pour pouvoir retrouver la mine d'or.",answer:true,points:1},
    {id:"q11",section:"Vrai ou Faux",type:"tf",text:"La pépite d'or que Nils offre à Alexis est celle que le renne avait découverte sous la glace.",answer:false,points:1},
    {id:"q12",section:"Vrai ou Faux",type:"tf",text:"Les voleurs sont arrêtés grâce aux informations données par Alexis sur le camion.",answer:true,points:1},
    {id:"q13",section:"Vocabulaire",type:"mcq",text:"« La pièce était jonchée de vêtements d'hiver. » — Que signifie jonchée ?",options:["Rangée soigneusement","Décorée avec soin","Couverte et encombrée","Vidée complètement"],answer:2,points:1},
    {id:"q14",section:"Vocabulaire",type:"mcq",text:"« Ses sourcils broussailleux étaient blancs. » — Que signifie broussailleux ?",options:["Soigneusement taillés","Très fins et délicats","Entièrement rasés","Épais, touffus et en désordre"],answer:3,points:1},
    {id:"q15",section:"Vocabulaire",type:"mcq",text:"« Je demandai à brûle-pourpoint : Meri, tu connais ces hommes ? » — Que signifie à brûle-pourpoint ?",options:["Avec beaucoup de colère","D'une voix très douce","De façon soudaine et directe, sans prévenir","En chuchotant pour ne pas être entendu"],answer:2,points:1},
    {id:"q16",section:"Synthèse",type:"mcq",text:"Un seul de ces trois résumés est totalement correct. Lequel ?",options:["Résumé A : Alexis, un garçon belge, part en Laponie rendre visite à son oncle Nils. Sur place, il rencontre Meri, la fille du père Noël, et tous deux découvrent un jeune renne aux sabots d'or que des voleurs tentent de s'approprier. Alexis choisit de libérer l'animal plutôt que de le garder pour trouver la mine d'or. Nils lui révèle alors que ce renne apparaît tous les soixante ans dans leur famille, et lui offre une pépite d'or qu'il avait lui-même récupérée lors de sa propre rencontre avec le renne.","Résumé B : Les deux enfants décident d'attacher le renne à un bouleau, mais les voleurs reviennent et libèrent l'animal. À la fin, Nils récompense Alexis en lui donnant une motoneige.","Résumé C : Alexis et Meri gardent le renne attaché pour pouvoir exploiter la mine et s'enrichir, et Nils approuve leur décision."],answer:0,points:1}
  ]}
];
